101	void OpencoreImpl::CreateCoreAUXV(int pid) {
102	    char filename[32];
103	    lp64::Auxv vec;
104	    snprintf(filename, sizeof(filename), "/proc/%d/auxv", pid);
105	
106	    FILE *fp = fopen(filename, "rb");
107	    if (fp != nullptr) {
108	        while (fread(&vec, sizeof(vec), 1, fp)) {
109	            auxvnum++;
110	        }
111	        fseek(fp, 0, SEEK_SET);
112	
113	        auxv.assign(auxvnum, {});
114	
115	        int index =0;
116	        while (fread(&vec, sizeof(vec), 1, fp)) {
117	            auxv[index].type = vec.type;
118	            auxv[index].value = vec.value;
119	            index++;
120	        }
121	
122	        fclose(fp);
123	    }
124	}
