60	void OpencoreImpl::ParseProcessMapsVma(int pid) {
61	    ParseMaps(pid, maps);
62	    if (!maps.size())
63	        return;
64	
65	    phdr.assign(maps.size(), {});
66	    file.assign(maps.size(), {});
67	
68	    for (int index = 0; index < maps.size(); ++index) {
69	        Opencore::VirtualMemoryArea& vma = maps[index];
70	        ParserPhdr(index, vma);
71	        ParserNtFile(index, vma);
72	    }
73	}
