186	void OpencoreImpl::WriteCoreAUXV(FILE* fp) {
187	    Elf32_Nhdr elf_nhdr;
188	    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
189	    elf_nhdr.n_descsz = sizeof(lp32::Auxv) * auxvnum;
190	    elf_nhdr.n_type = NT_AUXV;
191	
192	    char magic[8];
193	    memset(magic, 0, sizeof(magic));
194	    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
195	
196	    fwrite(&elf_nhdr, sizeof(Elf32_Nhdr), 1, fp);
197	    fwrite(magic, sizeof(magic), 1, fp);
198	
199	    int index = 0;
200	    while (index < auxvnum) {
201	        fwrite(&auxv[index], sizeof(lp32::Auxv), 1, fp);
202	        index++;
203	    }
204	}
